import{_ as e,o as a,c as i,e as l}from"./app-25fa875f.js";const s={},n=l(`<h1 id="chapter-8-5-基于栈的字节码解释执行引擎" tabindex="-1"><a class="header-anchor" href="#chapter-8-5-基于栈的字节码解释执行引擎" aria-hidden="true">#</a> Chapter 8.5 - 基于栈的字节码解释执行引擎</h1><p>Created by : Mr Dk.</p><p>2020 / 01 / 30 23:12 🧨🧧</p><p>Ningbo, Zhejiang, China</p><hr><h2 id="_8-5-基于栈的字节码解释执行引擎" tabindex="-1"><a class="header-anchor" href="#_8-5-基于栈的字节码解释执行引擎" aria-hidden="true">#</a> 8.5 基于栈的字节码解释执行引擎</h2><h3 id="_8-5-1-解释执行" tabindex="-1"><a class="header-anchor" href="#_8-5-1-解释执行" aria-hidden="true">#</a> 8.5.1 解释执行</h3><p>在 Java 初生的年代，解释执行还是比较准确的，但当主流 JVM 内部都包含了即时编译器后，Class 文件中的代码到底是被解释执行还是编译执行，就只有 JVM 自己才能判断了。</p><h3 id="_8-5-2-基于栈的指令集与基于寄存器的指令集" tabindex="-1"><a class="header-anchor" href="#_8-5-2-基于栈的指令集与基于寄存器的指令集" aria-hidden="true">#</a> 8.5.2 基于栈的指令集与基于寄存器的指令集</h3><p>Javac 编译器输出的字节码指令流，是一种基于栈的指令集架构，指令大部分都是 <strong>零地址指令</strong> (没有地址)，依赖 <strong>操作数栈</strong> 进行工作。常用的指令级架构是基于寄存器的指令集，比如 x86 的 <strong>二地址指令集</strong>。</p><p>JVM 的指令通常不带参数，使用操作数栈中的数据作为输入，运算结果存储在操作数栈中。</p><div class="language-assembly line-numbers-mode" data-ext="assembly"><pre class="language-assembly"><code>iconst_1
iconst_1
iadd
istore_0
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>而基于寄存器的指令包含独立的输入参数，依赖寄存器来访问和存储数据：</p><div class="language-assembly line-numbers-mode" data-ext="assembly"><pre class="language-assembly"><code>mov eax, 1
add eax, 1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>基于栈的指令集 - 优势：</p><ul><li>可移植 <ul><li>寄存器由硬件提供，程序依赖寄存器不可避免地受到体系结构的约束</li><li>JVM 可以由虚拟机实现自行决定把访问最频繁的数据放到寄存器中</li></ul></li><li>代码相对紧凑 <ul><li>一个字节</li><li>没有地址参数</li></ul></li><li>编译器实现简单 <ul><li>不需考虑空间分配问题</li><li>所需空间都在栈上操作</li></ul></li></ul><p>劣势：</p><ul><li>理论执行速度较慢 (特指解释执行)</li><li>代码紧凑，但是实现相同功能所需的指令数量较多</li><li>栈的实现在内存中，对于 CPU 来说，内存是执行速度的瓶颈</li></ul><p>JVM 会对指令的执行过程做出一系列优化以提高性能。JVM 中的 <strong>解释器</strong> 和 <strong>即时编译器</strong> 都会对输入的字节码进行优化。</p>`,19),r=[n];function d(t,c){return a(),i("div",null,r)}const o=e(s,[["render",d],["__file","Chapter 8.5 - 基于栈的字节码解释执行引擎.html.vue"]]);export{o as default};
